/**
 * Parses a duration string and returns the equivalent duration in milliseconds.
 *
 * @param {string} str - A duration string with a number and unit (e.g., "5s", "2.5h", "500ms")
 * @returns {number} The duration in milliseconds, rounded to the nearest integer
 * @throws {Error} Throws an error if the duration string format is invalid
 *
 * @example
 * parseDuration("5s");      // Returns 5000
 * parseDuration("2.5h");    // Returns 9000000
 * parseDuration("500ms");   // Returns 500
 * parseDuration("3d");      // Returns 259200000
 */
function parseDuration(str) {
  const m = /^(\d+(?:\.\d+)?)(ms|s|m|h|d)$/.exec(str.trim());
  if (!m) throw new Error('Invalid duration: ' + str);
  const n = parseFloat(m[1]);
  const u = m[2];
  const mult = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 }[u];
  return Math.round(n * mult);
}
